UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('81f4c86f-9107-415d-945f-e36309cce4b1'::uuid, 'La surveillance de la tension est primordiale, le tensiomètre permet de vérifier régulièrement votre pression artérielle.'),('ffc19359-db8d-46f0-80ae-127a0d757b36'::uuid, 'Les IEC agissent sur la pression artérielle, les oméga 3 contribuent au maintien d''une fonction cardiaque normale.'),('e86b511a-9f17-4e2d-a779-48065dd64604'::uuid, 'Certains traitements peuvent impacter la fonction cardiaque, la Coenzyme Q10 est essentiel à la production d''énergie cellulaire du cœur.'),('532e5f8c-eb29-4b07-b29f-5f32aff189ec'::uuid, 'La surveillance de la tension est primordiale, le tensiomètre permet de vérifier régulièrement votre pression artérielle.'),('56c504d6-b010-46ff-8706-40fef1e5618b'::uuid, 'Les IEC et diurétiques agissent sur le système cardiovasculaire, les oméga 3 aident à maintenir une fonction cardiaque saine.'),('7ad18999-51aa-40c4-81dc-e2912dc2bd22'::uuid, 'Les IEC et diurétiques agissent sur le système cardiovasculaire, les oméga 3 aident à maintenir une fonction cardiaque saine.'),('eda96cf0-faa8-4606-9e88-aea816ef9959'::uuid, 'Les IEC et diurétiques agissent sur le système cardiovasculaire, les oméga 3 aident à maintenir une fonction cardiaque saine.'),('8dbabf4b-731c-43d2-b3f5-7881a549054b'::uuid, 'Les immunosuppresseurs affaiblissent le système immunitaire, la vitamine D3 renforce les défenses naturelles de votre organisme.'),('5bf2b9ca-8050-4940-aa00-ba514df70f90'::uuid, 'Le traitement peut générer de la fatigue, le magnésium B6 contribue à réduire l''épuisement et le stress corporel.'),('829c67b1-e007-49fb-a5fa-598d0e2e4a29'::uuid, 'Les traitements peuvent affecter la densité osseuse, et la vitamine D3 renforce les os en améliorant l''absorption du calcium.'),('f31f8721-5e4a-436d-9327-0d52232e2bb7'::uuid, 'Les contraintes associées aux traitements peuvent générer du stress, et le magnésium B6 aide à diminuer la fatigue nerveuse et musculaire.'),('2803cb1f-838c-4a50-93e6-629152c4b2b0'::uuid, 'Les traitements peuvent perturber la flore intestinale, et les probiotiques rééquilibrent la digestion et soutiennent l''immunité.'),('dd3c44d3-0d72-44b7-9248-3fb26eec374d'::uuid, 'Certains traitements peuvent fragiliser l''ossature, et la vitamine D3 aide à réguler le métabolisme du calcium pour des os résistants.'),('7ffce940-f536-44ca-b5aa-2542b09b9215'::uuid, 'Les traitements peuvent engendrer de la fatigue, et le magnésium B6 participe à la réduction de l''épuisement physique et mental.'),('432ed373-76ba-4bd0-bfdd-5fa640a3079e'::uuid, 'Les médicaments peuvent irriter le système digestif, et les probiotiques contribuent à restaurer l''équilibre de la flore intestinale.'),('e45b0369-c3b3-40a6-8607-f79b1e612467'::uuid, 'Les inhibiteurs de tyrosine kinase peuvent impacter la santé osseuse, et la vitamine D3 aide à maintenir une minéralisation normale des os.'),('02f1717f-eaba-401d-90d4-eced83f8c97d'::uuid, 'La prise de ce traitement peut provoquer de la fatigue, et le magnésium B6 contribue à réduire l''épuisement et les tensions musculaires.'),('751959f1-0181-4f78-af77-d87a1fede944'::uuid, 'Les INNTI peuvent influencer la résorption osseuse, et la vitamine D3 est essentielle pour un bon métabolisme calcique et osseux.'),('22d55aee-6e19-47d1-81af-dc26f7decedd'::uuid, 'La fatigue est un effet secondaire fréquent, et le magnésium B6 aide à combattre l''épuisement physique par son action sur l''énergie cellulaire.'),('2793a415-fd76-4099-88b4-313515b41047'::uuid, 'Le traitement par insuline nécessite une surveillance constante; ce lecteur aide à mesurer avec précision votre glycémie pour un contrôle optimal.'),('5a8ab037-980b-4674-b8f0-15f5a2535dc6'::uuid, 'Pour les personnes sous insuline, le chrome et la cannelle aident à optimiser le métabolisme des sucres pour une meilleure régulation glycémique.'),('b9bf0b9a-5d7f-4ab8-af37-892d749085df'::uuid, 'Le diabète peut causer une sécheresse cutanée et des lésions aux pieds, cette crème hydrate et protège l''intégrité de la peau.'),('8e29e1aa-7579-496c-ad0c-a9e0fdfbb259'::uuid, 'L''insuline rapide demande une précision accrue, et ce lecteur FreeStyle permet une surveillance glycémique facile pour ajuster le dosage.'),('2dd660d3-7ee3-4af1-8e8c-334c252bb66e'::uuid, 'Le chrome et la cannelle facilitent le métabolisme des glucides, soutenant ainsi l''action de l''insuline rapide pour une meilleure gestion glycémique.'),('1dc3b644-7e1a-4674-bc78-fbd0ca24f101'::uuid, 'La neuropathie diabétique peut rendre les pieds sensibles, cette crème hydratante protège la barrière cutanée contre les risques de lésions.'),('5aaf7e89-892b-4ce9-82c9-786cbd9d6a7e'::uuid, 'Une surveillance glycémique régulière est cruciale avec l''insuline ultra-longue, et ce lecteur permet un suivi précis de vos niveaux de sucre.'),('d8aa201a-da9f-4d06-8767-a2a8d7325d54'::uuid, 'Le chrome et la cannelle aident à l''assimilation des sucres, potentialisant l''effet de l''insuline ultra-longue pour stabiliser la glycémie.'),('24b9d3c9-4b77-44b7-9acf-85649b98d53d'::uuid, 'Une hygiène rigoureuse est essentielle avec le diabète, et cette crème nourrit et protège la peau fragilisée des pieds contre les infections.'),('845d6b12-cbf6-4a19-8644-b74ab11781f1'::uuid, 'La vitamine D3 participe au bon fonctionnement immunitaire, renforçant les défenses naturelles du corps face aux affections diverses.'),('bf5f487a-0a07-416d-a90b-644e2cf9655d'::uuid, 'Le stress peut avoir un impact négatif, et le magnésium B6 aide à réguler le système nerveux pour réduire la fatigue et les tensions.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;